				sessionID: "sess_1",
				role: "assistant",
				parts: [makeTextPart("p_a2", "The answer is 6.")],
			});

			// Restart poller WITHOUT seed → demonstrates the re-emission bug
			client.getMessages.mockResolvedValue([
				userMsg1,
				assistantMsg1,
				userMsg2,
