			// No events from seed
			expect(events.filter((e) => e.type === "thinking_delta")).toHaveLength(0);

			// Reasoning grows
			client.getMessages.mockResolvedValue([
				makeMessage({
					id: "msg_1",
					sessionID: "sess_1",
					parts: [makeReasoningPart("p1", "Initial thought and more")],
