			expect(client.getMessages).toHaveBeenCalledTimes(1);
			expect(client.getMessages).toHaveBeenCalledWith("sess_1");

			// After one interval, second poll fires
			await vi.advanceTimersByTimeAsync(POLL_INTERVAL_MS);
