			poller.stopPolling();
			events.length = 0;

			// Turn 2 messages appear
			const userMsg2 = makeMessage({
				id: "msg_u2",
				sessionID: "sess_1",
				role: "user",
				parts: [makeTextPart("p_u2", "And 3+3?")],
