			await vi.advanceTimersByTimeAsync(IDLE_TIMEOUT_MS + POLL_INTERVAL_MS);

			expect(poller.isPolling()).toBe(false);
		});

		it("content detection resets the idle timer", async () => {
			const msg = makeMessage({
				id: "msg_1",
				sessionID: "sess_1",
				parts: [makeTextPart("p1", "Hello")],
			});
