		it("seeded with undefined behaves like unseeded (backward compatible)", async () => {
			const msg = makeMessage({
				id: "msg_1",
				sessionID: "sess_1",
				parts: [makeTextPart("p1", "Hello")],
			});
			const client = createMockClient([msg]);
