		const roots = await this.listSessions({
			roots: true,
			statuses: options?.statuses,
		});
		send({ type: "session_list", sessions: roots, roots: true });

		this.listSessions({ statuses: options?.statuses })
			.then((all) => {
				send({ type: "session_list", sessions: all, roots: false });
			})
			.catch((err) => {
