	sessions: SessionDetail[],
	statuses?: Record<string, SessionStatus>,
	lastMessageAt?: ReadonlyMap<string, number>,
	forkMeta?: ReadonlyMap<string, ForkEntry>,
	pendingQuestionCounts?: ReadonlyMap<string, number>,
