// ─── Types ───────────────────────────────────────────────────────────────────

export interface SessionManagerOptions {
	client: OpenCodeClient;
	/** Number of messages to load per page (default 50) */
	historyPageSize?: number;
	/** Logger for diagnostics */
	log?: Logger;
	/** Project directory (for debug logging) */
	directory?: string;
